// LESSON: Reference Page 1 - Collections: begrepp.
// You will learn: Choose Collection, Set, Iterator, and Queue operations by purpose.
class Prog2Reference429 {
  // EXEMPEL 1: List bevarar ordning, index och dubletter.
  static String listExample() {
    java.util.List<String> names = new java.util.ArrayList<String>();
    names.add("Ada");
    names.add("Ada");
    return names.get(0) + names.size();
  }
  // EXEMPEL 2: Set lagrar unika varden utan index.
  static int setExample() {
    java.util.Set<String> usernames = new java.util.HashSet<String>();
    usernames.add("sam");
    usernames.add("sam");
    return usernames.size();
  }
  // EXEMPEL 3: Queue och Deque modellerar ko eller stack.
  static String queueExample() {
    java.util.Queue<String> queue = new java.util.ArrayDeque<String>();
    queue.add("first");
    queue.add("second");
    return queue.remove();
  }
}
